// Build script-type-specific NEPQ instructions and field guidance
const scriptType = $('Webhook').item.json.body.script_type;

const scriptConfigs = {
  discovery: {
    nepq_focus: 'Problem Identification + Consequence Questions. Use NEPQ stages: Connecting Questions → Situation Questions → Problem Awareness Questions → Consequence Questions. Goal: make the prospect feel the pain of their current situation and see the cost of inaction.',
    required_fields: 'script_title, opening (connecting statement), discovery_questions (array of 6-8 NEPQ-sequenced questions), objection_handlers (array of 2-3 early resistance handlers), close (next-step ask / permission to continue), followup_lines (array of 2 lines if they go cold)',
    output_note: 'discovery_questions should escalate: start neutral, then dig into consequences. Each question should be max 1 sentence.'
  },
  objection_handler: {
    nepq_focus: 'Objection Neutralization using NEPQ Reframing. For each objection: Acknowledge → Isolate → Reverse with a question. Never defend — always redirect with curiosity. Common objections: price, timing, need to think, need to talk to spouse/partner, already have a solution.',
    required_fields: 'script_title, opening (pattern interrupt opener), discovery_questions (array of 2-3 clarifying questions to uncover real objection), objection_handlers (array of 5 fully scripted objection responses with setup + reframe question), close (re-ask after reframe), followup_lines (array of 2 lines for follow-through)',
    output_note: 'Each objection_handler must include: objection_trigger, acknowledge_line, reframe_question.'
  },
  closing: {
    nepq_focus: 'Commitment-Based Closing using NEPQ Solution Awareness + Consequence of Inaction. Do NOT pitch features. Close by referencing their own stated pain and desired outcome. Use assumptive and alternative closes layered with consequence questions.',
    required_fields: 'script_title, opening (transition from discovery to close), discovery_questions (array of 2-3 confirmation questions to lock in their pain/desire), objection_handlers (array of 3 close-resistance handlers), close (3-step close sequence: consequence → solution bridge → commitment ask), followup_lines (array of 3 urgency-based follow-up lines)',
    output_note: 'close field must contain a multi-step sequence, not a single line. Reference their stated goals.'
  },
  followup_voicemail: {
    nepq_focus: 'Pattern-Interrupt Voicemail using NEPQ Curiosity Gap. The goal is a callback — not a pitch. Create intrigue by referencing their specific situation without revealing the solution. Keep it under 30 seconds when spoken aloud.',
    required_fields: 'script_title, opening (first 2 sentences of voicemail — must create curiosity), discovery_questions (empty array — not applicable), objection_handlers (empty array — not applicable), close (the callback ask — one sentence), followup_lines (array of 3 voicemail variations: Day 2, Day 5, Day 10 follow-ups)',
    output_note: 'opening must be under 40 words. followup_lines should escalate urgency across Day 2 / Day 5 / Day 10.'
  }
};

const config = scriptConfigs[scriptType] || scriptConfigs['discovery'];

return [
  {
    json: {
      ...config,
      script_type: scriptType,
      user_id: $('Webhook').item.json.body.user_id,
      offer_name: $('Webhook').item.json.body.offer_name,
      target_persona: $('Webhook').item.json.body.target_persona,
      price_point: $('Webhook').item.json.body.price_point,
      niche: $('Fetch Business Profile').item.json.niche,
      icp: $('Fetch Business Profile').item.json.icp,
      value_props: $('Fetch Business Profile').item.json.value_props,
      brand_voice: $('Fetch Business Profile').item.json.brand_voice,
      company_name: $('Fetch Business Profile').item.json.company_name,
      system_prompt: $('Fetch System Prompt').item.json.system_prompt
    }
  }
];

