=You are an elite sales script writer trained in NEPQ (Neuro-Emotional Persuasion Questioning) by Jeremy Miner. Your scripts never pitch — they pull. Every line is designed to make the prospect feel understood, see their own problem clearly, and self-qualify.

---

SCRIPT TYPE: {{ $json.script_type }}

NEPQ FRAMEWORK FOCUS:
{{ $json.nepq_focus }}

BUSINESS CONTEXT:
- Company: {{ $json.company_name }}
- Niche: {{ $json.niche }}
- Offer Name: {{ $json.offer_name }}
- Price Point: {{ $json.price_point }}
- Target Persona: {{ $json.target_persona }}
- ICP (Ideal Customer Profile): {{ $json.icp }}
- Value Propositions: {{ $json.value_props }}
- Brand Voice: {{ $json.brand_voice }}

OUTPUT REQUIREMENTS:
{{ $json.required_fields }}

ADDITIONAL NOTES:
{{ $json.output_note }}

---

You MUST respond with ONLY a valid JSON object — no markdown, no code fences, no explanation. Use this exact schema:
{
  "script_title": "string",
  "opening": "string",
  "discovery_questions": ["string"],
  "objection_handlers": ["string or object"],
  "close": "string",
  "followup_lines": ["string"]
}

parameters.jsCode:
const raw = $input.item.json;
const inputData = $('Build NEPQ Context').item.json;

// Extract text from Claude response
let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(raw));
}

// Strip markdown fences if Claude wrapped JSON anyway
const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.substring(0, 400));
}

// Validate required keys
const required = ['script_title', 'opening', 'discovery_questions', 'objection_handlers', 'close', 'followup_lines'];
for (const key of required) {
  if (!(key in parsed)) {
    throw new Error(`Missing required key in Claude response: ${key}`);
  }
}

// Ensure arrays are arrays
if (!Array.isArray(parsed.discovery_questions)) parsed.discovery_questions = [];
if (!Array.isArray(parsed.objection_handlers)) parsed.objection_handlers = [];
if (!Array.isArray(parsed.followup_lines)) parsed.followup_lines = [];

return {
  json: {
    user_id: inputData.user_id,
    script_type: inputData.script_type,
    offer_name: inputData.offer_name,
    target_persona: inputData.target_persona,
    price_point: inputData.price_point,
    script_title: parsed.script_title,
    opening: parsed.opening,
    discovery_questions: parsed.discovery_questions,
    objection_handlers: parsed.objection_handlers,
    close: parsed.close,
    followup_lines: parsed.followup_lines
  }
};

